module shift_register(clk, reset, load, data_in, shift_in, q);

    input clk;
    input reset;
    input load;
    input [7:0] data_in;
    input shift_in;
    output [7:0] q;
    reg [7:0] q;
    initial q = 8'b00000000;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            if (reset)
                q <= 8'b00000000;
            else if (load)
                q <= data_in;
            else
                q <= {q[6:0], shift_in};
        end

endmodule
